function dfsTraversal(graph, start) {
  const visited = new Set();
  const result = [];

  function dfs(node) {
    if (visited.has(node)) return;
    visited.add(node);
    result.push(node);
    const neighbors = graph[node] || [];
    for (const next of neighbors) {
      dfs(next);
    }
  }

  dfs(start);
  return result;
}

IList<int> DfsTraversal(IList<IList<int>> graph, int start)
{
    var result = new List<int>();
    if (graph == null || start < 0 || start >= graph.Count) return result;

    var seen = new bool[graph.Count];
    var stack = new Stack<int>();
    stack.Push(start);

    while (stack.Count > 0)
    {
        int node = stack.Pop();
        if (node < 0 || node >= graph.Count || seen[node]) continue;

        seen[node] = true;
        result.Add(node);

        for (int i = graph[node].Count - 1; i >= 0; i--)
        {
            int nei = graph[node][i];
            if (nei >= 0 && nei < graph.Count && !seen[nei]) stack.Push(nei);
        }
    }

    return result;
}

